css:
.loader {
  width: 40px;
  aspect-ratio: 1;
  background: linear-gradient(45deg, #0000 50%, #00AAFF 0), linear-gradient(-45deg, #0000 50%, #FF00AA 0), #00AAFF;
  background-size: 200% 200%;
  background-repeat: no-repeat;
  animation: l2 1.5s infinite;
}
@keyframes l2 {
  0% { background-position: bottom left, bottom right; }
  30%, 50% { background-position: bottom left, top left; }
  80%, 100% { background-position: top right, top left; }
}
